/**
 * Generate HeyGen firewall config.
 *
 * Data source: https://docs.heygen.com/reference/authentication
 *
 * HeyGen is an AI video generation platform.
 * Uses custom "X-Api-Key" header (not Bearer).
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.heygen.com/reference/authentication";
// Token format not publicly documented; using generic placeholder
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalC";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from HeyGen API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:heygen",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const heygenFirewall = {",
    '  name: "heygen",',
    '  description: "HeyGen API",',
    "  placeholders: {",
    `    HEYGEN_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.heygen.com",',
    "      auth: {",
    "        headers: {",
    '          "X-Api-Key": "${{ secrets.HEYGEN_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://upload.heygen.com",',
    "      auth: {",
    "        headers: {",
    '          "X-Api-Key": "${{ secrets.HEYGEN_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating HeyGen firewall config...");
  const ts = generateTypeScript();
  writeOutput("heygen", ts, import.meta.dirname);
}
